import type { Question, Subject } from '../types'

const tq = (id: string, question: string, answer: string, subject: Subject): Question => ({
  id,
  question,
  options: [],
  answer,
  explanation: '',
  subject,
})

export const THEORY_MARKETING: Question[] = [
  tq('tmk1', 'Define marketing according to the American Marketing Association and explain its importance in an economy.', 'Marketing is the process of planning and executing the conception, pricing, promotion, and distribution of ideas, goods, and services to create exchanges that satisfy individual and organisational objectives. Importance: drives economic growth by stimulating demand, creates employment, improves living standards, facilitates exchange, informs consumers, builds brands, and supports other business functions.', 'Marketing'),
  tq('tmk2', 'Distinguish between needs, wants, and demand in marketing. Give two examples of each.', 'Needs: basic necessities for survival — food, water, shelter, clothing. Wants: culturally shaped desires for specific satisfiers — wanting a hamburger (want) when hungry (need). Demand: wants backed by purchasing power — wanting a car and having the money to buy it. Marketers influence wants and stimulate demand but do not create needs.', 'Marketing'),
  tq('tmk3', 'Explain the five marketing management philosophies (orientations) with examples.', '(1) Production concept: consumers prefer widely available, low-cost products (e.g., Henry Ford\'s Model T). (2) Product concept: consumers favour quality/innovative products (e.g., Apple). (3) Selling concept: aggressive selling needed for unsought goods (e.g., insurance). (4) Marketing concept: focus on customer needs/wants (e.g., Amazon). (5) Societal marketing concept: consider consumer wants, company requirements, and society\'s long-term interests (e.g., Patagonia, ethical brands).', 'Marketing'),
  tq('tmk4', 'Describe the 4Ps of the marketing mix and explain how each element contributes to a successful marketing strategy.', 'Product: the good/service offered — quality, design, features, branding, packaging. Price: the amount customers pay — pricing strategy, discounts, credit terms. Place: distribution channels — retail, wholesale, online, logistics. Promotion: communication to inform/persuade — advertising, PR, sales promotion, personal selling, digital marketing. Each P must be integrated and consistent to create a cohesive value proposition targeting the identified market segment.', 'Marketing'),
  tq('tmk5', 'Explain the extended marketing mix (7Ps) for services marketing. What additional 3Ps are added and why?', 'For services, 3 additional Ps: (5) People: all human actors in service delivery — employees, customers, other customers. (6) Process: procedures, mechanisms, flow of activities — service delivery systems, customer management. (7) Physical evidence: tangible cues — facilities, equipment, staff appearance, brochures, website. These are added because services are intangible, inseparable, variable, and perishable, requiring management of the customer\'s entire service experience.', 'Marketing'),
  tq('tmk6', 'Discuss the stages of the product life cycle and the appropriate marketing strategies for each stage.', 'Stages: (1) Introduction — low sales, high costs, create awareness. Strategy: skimming or penetration pricing, heavy promotion. (2) Growth — sales rise, profits appear, competitors enter. Strategy: improve quality, new segments, build brand. (3) Maturity — sales peak, competition intense, profits stable/declining. Strategy: modify product/market/mix, price competition. (4) Decline — sales fall, profits drop. Strategy: maintain, harvest (reduce costs), or divest (discontinue).', 'Marketing'),
  tq('tmk7', 'Define market segmentation and explain the four main bases for segmenting consumer markets.', 'Market segmentation: dividing a market into distinct groups with different needs/characteristics. Bases: (1) Geographic — region, climate, city size, population density. (2) Demographic — age, gender, income, education, occupation, family size. (3) Psychographic — lifestyle, personality, values, social class. (4) Behavioural — usage rate, benefits sought, brand loyalty, occasion, user status. Effective segmentation requires segments to be measurable, accessible, substantial, differentiable, and actionable.', 'Marketing'),
  tq('tmk8', 'Distinguish between undifferentiated, differentiated, concentrated, and micromarketing targeting strategies.', 'Undifferentiated (mass marketing): same product for all segments — ignores differences. Differentiated (segmented marketing): different offerings for different segments (e.g., Toyota with different car models). Concentrated (niche marketing): focus on one segment (e.g., Rolls-Royce). Micromarketing: tailoring to individual customers — local marketing (neighbourhood) or individual marketing (customisation, one-to-one). Each strategy has different cost/reach implications.', 'Marketing'),
  tq('tmk9', 'Explain the concept of positioning and discuss how marketers use positioning maps. Give an example.', 'Positioning: designing the company\'s offering and image to occupy a distinctive place in the target market\'s mind. Positioning map (perceptual map): a visual tool showing consumer perceptions of brands on key attributes (e.g., price vs quality). Example: Volvo positions on safety, BMW on performance, Toyota on reliability. Positioning strategies: attribute, benefit, user, competitor, quality/price, product class. Repositioning: changing the brand\'s position in response to market changes.', 'Marketing'),
  tq('tmk10', 'Describe the consumer buying decision process, outlining all five stages.', 'Stages: (1) Need recognition — consumer recognises a problem or need (triggered by internal or external stimuli). (2) Information search — internal (memory, experience) and external (family, friends, commercial, public sources). (3) Evaluation of alternatives — compare brands on attributes, consider evaluative criteria. (4) Purchase decision — choose product/brand, decide when/where to buy. (5) Post-purchase behaviour — satisfaction (if expectations met) or dissatisfaction (cognitive dissonance). Marketers must manage each stage to influence the outcome.', 'Marketing'),
  tq('tmk11', 'Explain the factors influencing consumer buying behaviour: cultural, social, personal, and psychological.', 'Cultural: culture (values, beliefs), subculture (nationality, religion, ethnic groups), social class (income, education, occupation). Social: reference groups (family, friends, online communities), family (roles and influence), roles and status. Personal: age and life-cycle stage, occupation, economic situation, lifestyle, personality and self-concept. Psychological: motivation (Maslow\'s hierarchy), perception (selective attention/distortion/retention), learning (drives, stimuli, cues, responses, reinforcement), beliefs and attitudes. All factors interact to shape purchase decisions.', 'Marketing'),
  tq('tmk12', 'What is a brand? Explain the functions of branding to both buyers and sellers.', 'Brand: a name, term, sign, symbol, or design (or combination) that identifies the products of one seller and differentiates them from competitors. Functions to buyers: identifies source, assigns responsibility, reduces search costs, signals quality, provides reassurance. Functions to sellers: simplifies product handling, provides legal protection, enables market segmentation, builds customer loyalty, creates brand equity (the added value a brand gives a product), allows premium pricing.', 'Marketing'),
  tq('tmk13', 'Discuss the concept of brand equity and the four dimensions that measure it (CBBE model).', 'Brand equity: the differential effect that brand knowledge has on consumer response to marketing. Customer-Based Brand Equity (CBBE) dimensions: (1) Brand awareness — how easily consumers recall/recognise the brand. (2) Brand associations — attributes, benefits, attitudes linked to the brand. (3) Perceived quality — customer\'s perception of overall product quality. (4) Brand loyalty — attachment and repeat purchase behaviour. Strong brands have high brand equity, leading to greater revenue, cost advantages, and competitive protection.', 'Marketing'),
  tq('tmk14', 'Explain the roles of packaging in marketing and discuss the factors considered in packaging design.', 'Packaging roles: (1) Protection — preserve product from damage, spoilage, contamination. (2) Containment — hold the product for handling and transport. (3) Information — communicate contents, usage, ingredients, expiry date. (4) Promotion — attract attention, convey brand image, differentiate at point of sale. (5) Convenience — easy to open, use, store, dispose. Factors in design: size, shape, colour, material, graphics, legal requirements (labelling, safety), cost, environmental sustainability (eco-friendly packaging).', 'Marketing'),
  tq('tmk15', 'Define advertising and explain the five main decisions in developing an advertising programme (the 5Ms).', 'Advertising: any paid form of non-personal communication about an organisation, product, service, or idea by an identified sponsor. 5Ms: (1) Mission — what are the advertising objectives (inform, persuade, remind)? (2) Money — what is the budget? (3) Message — what is the creative strategy (appeal, execution, tone)? (4) Media — which channels (TV, radio, print, digital, outdoor)? (5) Measurement — how to evaluate effectiveness (reach, frequency, impact, ROI).', 'Marketing'),
  tq('tmk16', 'Explain the objectives of promotion and describe the elements of the promotional mix.', 'Promotion objectives: inform (create awareness), persuade (stimulate purchase), remind (maintain top-of-mind awareness), build relationships. Promotional mix elements: (1) Advertising — mass media, non-personal, paid. (2) Personal selling — direct interaction, persuasive, expensive. (3) Sales promotion — short-term incentives (coupons, contests, discounts). (4) Public relations — build goodwill, manage image, unpaid media. (5) Direct marketing — targeted communication (mail, email, telemarketing). (6) Digital/internet marketing — social media, SEO, content marketing. The mix depends on product type, market, budget, and objectives.', 'Marketing'),
  tq('tmk17', 'Describe the process of developing new products (new product development stages).', 'NPD stages: (1) Idea generation — internal sources (R&D, employees) and external (customers, competitors, suppliers). (2) Idea screening — eliminate poor ideas, assess fit and feasibility. (3) Concept development and testing — develop detailed concept, test with target consumers. (4) Marketing strategy development — initial marketing plan. (5) Business analysis — sales, cost, profit projections. (6) Product development — prototype, technical and marketing testing. (7) Test marketing — limited launch in representative market. (8) Commercialisation — full-scale launch. Many ideas fail at each stage (funnel).', 'Marketing'),
  tq('tmk18', 'Explain the different types of distribution channels for consumer goods.', 'Distribution channels: (1) Direct (zero-level) — producer to consumer (e.g., farmers\' market, company website). (2) One-level — producer to retailer to consumer (e.g., car manufacturer selling through dealerships). (3) Two-level — producer to wholesaler to retailer to consumer (common for consumer packaged goods). (4) Three-level — producer to agent to wholesaler to retailer to consumer (used for wide geographic coverage). Channel selection depends on product characteristics, market factors, company resources, and environmental factors.', 'Marketing'),
  tq('tmk19', 'Discuss the factors that influence the choice of a distribution channel.', 'Factors: (1) Product factors — perishability, complexity, value, size/weight, customisation. Perishable products need shorter channels. (2) Market factors — customer characteristics, geographic concentration, order size, number of customers. (3) Company factors — financial resources, control desire, experience, product mix. (4) Competitive factors — competitors\' channels, avoiding or matching. (5) Environmental factors — economic conditions, legal restrictions, technology (internet enables direct channels). The optimal channel balances coverage, control, and cost.', 'Marketing'),
  tq('tmk20', 'Explain the concept of intensive, selective, and exclusive distribution strategies.', '(1) Intensive distribution: product available in as many outlets as possible (e.g., soft drinks, toothpaste, bread). Seeks maximum market coverage. (2) Selective distribution: product available in a limited number of outlets (e.g., electronics, furniture). Balances coverage with control. (3) Exclusive distribution: product available in only one outlet per area (e.g., luxury cars, high-end fashion). Maximum control, higher margins, limited coverage. Choice depends on product type — convenience goods use intensive, shopping goods use selective, speciality goods use exclusive.', 'Marketing'),
  tq('tmk21', 'Define pricing and explain the major internal and external factors affecting pricing decisions.', 'Pricing: the process of determining what a company will receive in exchange for its products. Internal factors: (1) Marketing objectives (survival, profit maximisation, market share, product quality). (2) Marketing mix strategy (price must be consistent with product, promotion, distribution). (3) Costs (fixed, variable, total cost — sets price floor). (4) Organisational considerations (who sets price). External factors: (1) Demand (price elasticity). (2) Competition (competitors\' prices). (3) Economic conditions (inflation, recession). (4) Government regulations (price controls, taxes).', 'Marketing'),
  tq('tmk22', 'Explain the following pricing strategies: (a) penetration pricing (b) skimming pricing (c) competitive pricing.', '(a) Penetration pricing: setting a low initial price to attract many customers and gain market share quickly. Used when market is price-sensitive, competition is expected, and economies of scale exist. (b) Skimming pricing: setting a high initial price to maximise profits from segments willing to pay more, then lowering over time. Used for innovative products, when demand is inelastic, or when competition can be delayed. (c) Competitive pricing: setting price based on competitors\' pricing — at, above, or below market price. Common in mature markets with similar products.', 'Marketing'),
  tq('tmk23', 'Discuss the different types of sales promotion aimed at consumers and trade intermediaries.', 'Consumer sales promotion: samples, coupons, cash refunds, price packs (BOGOF), premiums (gifts with purchase), contests/sweepstakes, loyalty programmes, point-of-purchase displays. Trade promotion: buying allowances (discount for volume), promotional allowances (payment for featuring product), free goods (free cases for purchasing certain quantity), cooperative advertising (manufacturer shares ad cost), sales contests (rewards for salespeople), trade shows. Trade promotions motivate intermediaries to stock, promote, and sell the product.', 'Marketing'),
  tq('tmk24', 'Explain the role of public relations (PR) in the promotional mix and describe the main PR tools.', 'PR: building good relationships with the company\'s various publics by obtaining favourable publicity, building a good corporate image, and handling unfavourable rumours/events. PR tools: (1) Press releases/News — newsworthy information to media. (2) Press conferences — direct media briefings. (3) Special events — sponsorships, grand openings, product launches. (4) Corporate identity materials — logos, uniforms, brochures. (5) Public service activities — community involvement, CSR initiatives. (6) Crisis management — handling negative publicity. PR is more credible than advertising but less controllable.', 'Marketing'),
  tq('tmk25', 'Describe the personal selling process, explaining each of the seven steps.', 'Personal selling process: (1) Prospecting — identifying potential customers. (2) Pre-approach — researching prospects, planning the sales call. (3) Approach — meeting the prospect, making a positive first impression. (4) Presentation — demonstrating the product, presenting features/benefits, using AIDA (Attention, Interest, Desire, Action). (5) Handling objections — addressing concerns and resistance. (6) Closing — asking for the order. (7) Follow-up — post-purchase service, building long-term relationship. Effective selling is consultative (solving customer problems) rather than manipulative.', 'Marketing'),
  tq('tmk26', 'Explain the difference between push strategy and pull strategy in promotion.', 'Push strategy: using personal selling and trade promotion to push the product through distribution channels — manufacturer promotes to wholesalers, wholesalers to retailers, retailers to consumers. Works well when brand loyalty is low, product is chosen at store, or product is new. Pull strategy: using advertising and consumer promotion to generate consumer demand that pulls the product through the channel — consumers demand from retailers, retailers from wholesalers, wholesalers from manufacturers. Most companies use a combination (push-pull strategy).', 'Marketing'),
  tq('tmk27', 'Define marketing research and describe the steps in the marketing research process.', 'Marketing research: the systematic design, collection, analysis, and reporting of data relevant to a specific marketing situation. Steps: (1) Define the problem and research objectives (exploratory, descriptive, or causal). (2) Develop the research plan — data sources (primary/secondary), research approach (observation, survey, experiment), instruments (questionnaire), sampling plan, contact methods. (3) Collect data — field work. (4) Analyse data — tabulate, analyse, interpret. (5) Present findings — report and recommendations. (6) Make decision — use findings for marketing decisions.', 'Marketing'),
  tq('tmk28', 'Distinguish between primary data and secondary data in marketing research. Give two examples of each and state their advantages and disadvantages.', 'Primary data: collected specifically for the current problem. Examples: surveys, focus groups, interviews, observation. Advantages: relevant, current, proprietary. Disadvantages: expensive, time-consuming, requires expertise. Secondary data: already exists, collected for another purpose. Examples: census data, company records, published reports, online databases. Advantages: quick, inexpensive. Disadvantages: may be outdated, not specific, quality uncertain. Researchers usually start with secondary data and collect primary data if needed.', 'Marketing'),
  tq('tmk29', 'Explain the concept of sampling in marketing research and describe probability and non-probability sampling methods.', 'Sampling: selecting a subset of a population to represent the whole. Probability sampling (every member has known chance): simple random, stratified (divide into subgroups, sample each), cluster (randomly select groups). Non-probability sampling (selection not random): convenience (easiest to reach), judgmental (researcher selects), quota (non-random from subgroups), snowball (referrals). Probability sampling allows generalisation; non-probability is cheaper and faster but may be biased.', 'Marketing'),
  tq('tmk30', 'Describe the different types of research approaches: observational, survey, and experimental.', '(1) Observational research: gathering data by observing relevant people, actions, and situations. Types: natural (real setting), contrived (simulated), mechanical (cameras, eye-tracking). (2) Survey research: gathering data through questionnaires/interviews. Types: telephone, mail, online, personal interview, focus group. Best for descriptive research. (3) Experimental research: controlling variables to establish cause-and-effect. Subjects randomly assigned to groups (control vs experimental), manipulate independent variable, measure effect on dependent variable. Best for causal research.', 'Marketing'),
  tq('tmk31', 'Explain the questionnaire design process and discuss the types of questions used in marketing research.', 'Questionnaire design process: (1) Determine information needed. (2) Choose question type. (3) Write clear, unbiased questions (avoid leading, loaded, double-barrelled). (4) Order questions logically (simple first, sensitive later). (5) Pilot test and revise. Question types: (1) Closed-ended — dichotomous (yes/no), multiple choice, Likert scale (agree-disagree), semantic differential (rate on bipolar adjectives). (2) Open-ended — completely unstructured, word association, sentence completion, story completion. Each type has different analysis implications.', 'Marketing'),
  tq('tmk32', 'Discuss the advantages and disadvantages of the following data collection methods: telephone, mail, personal interview, and online.', 'Telephone: fast, good response rates, but limited length, cannot show products, declining response due to caller ID. Mail: inexpensive, wide geographic coverage, but low response rate, slow, no interviewer bias. Personal interview: in-depth, flexible, can show products, but expensive, time-consuming, interviewer bias possible. Online: fast, inexpensive, easy to analyse, global reach, but sampling issues (digital divide), low response rates for emails, response quality concerns. Method choice depends on research objectives, budget, and target population.', 'Marketing'),
  tq('tmk33', 'Define the marketing environment and distinguish between the micro and macro environments.', 'Marketing environment: the actors and forces outside marketing that affect management\'s ability to build and maintain successful relationships with target customers. Microenvironment: actors close to the company that affect its ability to serve customers — company itself, suppliers, marketing intermediaries (resellers, distributors), customers (consumer, business, government), competitors, publics (media, government, local community). Macroenvironment: larger societal forces — demographic, economic, natural, technological, political/legal, cultural (PESTLE/DESTEP analysis).', 'Marketing'),
  tq('tmk34', 'Using the PESTLE framework, analyse the external macroenvironmental factors affecting a business.', 'PESTLE: (1) Political — government stability, tax policy, trade restrictions, regulations. (2) Economic — GDP growth, inflation, interest rates, unemployment, income. (3) Sociocultural — demographic trends, cultural values, lifestyle changes. (4) Technological — innovation, automation, R&D, digital transformation, internet penetration. (5) Legal — consumer protection laws, employment law, health/safety regulations. (6) Environmental — climate change, sustainability requirements, pollution controls, CSR expectations. Companies must monitor these factors and adapt their strategies accordingly.', 'Marketing'),
  tq('tmk35', 'Explain the marketing concept of customer value and customer satisfaction.', 'Customer value: the difference between the benefits a customer gets from owning/using a product and the costs of obtaining it (total customer benefit — total customer cost). Customer satisfaction: the degree to which a product\'s perceived performance matches a buyer\'s expectations. If performance < expectations = dissatisfied. If performance = expectations = satisfied. If performance > expectations = delighted. Companies create value by improving benefits (product, services, personnel, image) and reducing costs (monetary, time, energy, psychic). Satisfied customers are loyal.', 'Marketing'),
  tq('tmk36', 'Describe the factors that influence consumer behaviour in business-to-business (B2B) markets compared to consumer markets.', 'B2B markets: fewer but larger buyers, geographically concentrated, derived demand (demand from downstream), inelastic demand, fluctuating demand, professional purchasing (trained buyers), multiple decision-makers (buying centre), long-term relationships, direct purchasing, reciprocity. B2C markets: many small buyers, widely dispersed, direct demand, elastic demand, individual decision-making, impulse purchases possible. B2B buying process is more formal, complex, and rational with more negotiation. Relationship marketing is crucial in B2B.', 'Marketing'),
  tq('tmk37', 'Explain the concept of market demand and how to estimate it. Distinguish between market potential and sales potential.', 'Market demand: total volume of a product that would be bought by a defined customer group in a defined area/period under defined marketing conditions. Market potential: the upper limit of market demand (under ideal conditions). Sales potential: the maximum market share a company can reasonably achieve. Demand estimation methods: (1) Top-down — estimate total market, then company share. (2) Bottom-up — estimate from individual segments upwards. (3) Statistical — regression analysis, trend projection. (4) Expert opinion — Delphi method. (5) Customer surveys and test markets.', 'Marketing'),
  tq('tmk38', 'Discuss the factors that affect consumer adoption of new products.', 'Adoption process: mental stages from first hearing to regular use. Five product characteristics influencing adoption rate: (1) Relative advantage — degree better than existing alternatives. (2) Compatibility — consistency with values, experiences, needs. (3) Complexity — difficulty to understand/use. (4) Divisibility — can be tried on a limited basis. (5) Communicability — observable/describable to others. Adopter categories: innovators (venturesome), early adopters (respectable), early majority (deliberate), late majority (sceptical), laggards (traditional). Marketers target early adopters first.', 'Marketing'),
  tq('tmk39', 'Write short notes on the following pricing concepts: (a) price elasticity of demand (b) break-even analysis (c) mark-up pricing.', '(a) Price elasticity of demand: measure of responsiveness of quantity demanded to price changes. Elastic (>1): sales change significantly with price. Inelastic (<1): sales barely change. Factors: necessity vs luxury, substitutes available, proportion of income. (b) Break-even analysis: determines volume needed to cover costs. Break-even point = fixed cost / (price — variable cost). Above BEP = profit. (c) Mark-up pricing: adding a standard mark-up to cost. Retailer: mark-up on cost = (selling price - cost)/cost x 100. Mark-up on selling price = (SP - cost)/SP x 100.', 'Marketing'),
  tq('tmk40', 'Explain the concept of digital marketing and discuss its main tools.', 'Digital marketing: marketing activities conducted through digital channels/internet. Tools: (1) Search engine optimisation (SEO) — improving website visibility in organic search. (2) Search engine marketing (SEM) — paid search ads (PPC). (3) Social media marketing — promoting through platforms (Facebook, Instagram, LinkedIn, TikTok). (4) Content marketing — creating valuable content to attract/engage (blogs, videos, podcasts). (5) Email marketing — targeted messages to subscribers. (6) Affiliate marketing — partners earn commission for referrals. (7) Influencer marketing — partnering with social media influencers. (8) Mobile marketing — SMS, apps, location-based.', 'Marketing'),
  tq('tmk41', 'Describe how social media marketing differs from traditional advertising and explain its advantages.', 'Social media marketing: uses social platforms to engage with audiences, build communities, share content, and facilitate two-way communication. Traditional advertising: one-way broadcast through mass media. Advantages of social media: (1) Cost-effective — lower cost than TV/print. (2) Targeted — precise demographic, interest, behavioural targeting. (3) Interactive — conversations, user-generated content, feedback. (4) Measurable — real-time analytics (likes, shares, clicks, conversions). (5) Viral potential — content can spread quickly. (6) Brand building — humanises brand, builds loyalty. Challenges: algorithm changes, negative feedback, requires consistent content creation.', 'Marketing'),
  tq('tmk42', 'Explain content marketing and describe how it creates value for both businesses and consumers.', 'Content marketing: creating and distributing valuable, relevant, consistent content to attract and retain a clearly defined audience and drive profitable customer action. For consumers: provides useful information, solves problems, educates, entertains without hard selling. For businesses: builds brand authority and trust, improves SEO, generates leads at lower cost, nurtures prospects through the sales funnel, creates shareable assets. Formats: blog posts, videos, infographics, ebooks, whitepapers, podcasts, webinars, case studies. Effectiveness is measured by engagement, shares, lead generation, and conversion rates.', 'Marketing'),
  tq('tmk43', 'Define service marketing and explain the distinctive characteristics of services (IHIP).', 'Service marketing: marketing of intangible offerings where the customer does not own a physical good. IHIP characteristics: (1) Intangibility — services cannot be seen, tasted, felt before purchase (e.g., insurance, consultancy). Strategies: use tangible cues, testimonials, guarantees. (2) Heterogeneity — service quality varies by provider, time, customer. Strategies: standardisation, training, quality control. (3) Inseparability — production and consumption occur simultaneously, customer participates. Strategies: manage service encounters, train staff. (4) Perishability — services cannot be stored. Strategies: manage demand (pricing, reservations, part-time staff).', 'Marketing'),
  tq('tmk44', 'Explain the concept of service quality using the SERVQUAL model. Describe the five dimensions.', 'SERVQUAL: a framework for measuring service quality by comparing customer expectations with perceived performance. Five dimensions: (1) Reliability — ability to perform promised service dependably and accurately. (2) Responsiveness — willingness to help customers and provide prompt service. (3) Assurance — employees\' knowledge, courtesy, and ability to inspire trust. (4) Empathy — caring, individualised attention to customers. (5) Tangibles — appearance of physical facilities, equipment, personnel, materials. Gap model: gaps between customer expectations and perceptions arise from understanding, service design, service delivery, and communication gaps.', 'Marketing'),
  tq('tmk45', 'Discuss the concept of customer relationship management (CRM) and its importance in modern marketing.', 'CRM: the process of managing detailed information about individual customers and carefully managing customer touchpoints to maximise customer loyalty. Importance: (1) Retain existing customers (costs 5-7x more to acquire new customers). (2) Increase customer lifetime value (CLV = total revenue from customer over time). (3) Cross-selling and up-selling opportunities. (4) Personalised marketing. (5) Better customer service. (6) Word-of-mouth referrals. CRM technologies: sales force automation, customer service platforms, marketing automation, data analytics. Levels: basic (low-tech), reactive, accountable, proactive, partnership.', 'Marketing'),
  tq('tmk46', 'Explain what a marketing information system (MIS) is and describe its components.', 'Marketing information system (MIS): people, equipment, and procedures to gather, sort, analyse, evaluate, and distribute needed, timely, and accurate information to marketing decision-makers. Components: (1) Internal records — orders, sales, prices, costs, inventory, accounts receivable. (2) Marketing intelligence — everyday information about developments in the marketing environment (from salespeople, suppliers, publications, monitoring). (3) Marketing research — systematic studies for specific situations. (4) Marketing decision support system (DSS) — analytical tools, statistical models, software to interpret data and support decisions. The MIS provides the right information to the right people at the right time.', 'Marketing'),
  tq('tmk47', 'Distinguish between a product item, a product line, and a product mix. Explain the concepts of product line length and product mix width.', 'Product item: a specific version of a product (e.g., 500ml Coca-Cola). Product line: a group of related products (e.g., all Coca-Cola beverages). Product mix (assortment): the set of all product lines and items offered (e.g., all Coca-Cola Company products including Dasani, Sprite). Product line length: total number of items in a line (depth). Product mix width: number of different product lines. Product mix consistency: how closely related the lines are. Companies manage product lines through line stretching (adding beyond current range) and line filling (adding within current range).', 'Marketing'),
  tq('tmk48', 'Explain the concept of co-branding and its advantages and disadvantages.', 'Co-branding: two or more well-known brands combined in a single product or marketed together. Types: (1) Ingredient branding — one brand as component of another (Intel Inside). (2) Same-company co-branding — brands from same company (Kellogg\'s and Pop-Tarts). (3) Joint venture co-branding — different companies combine (Nike + Apple). (4) Retail co-branding — stores share location (Starbucks in Target). Advantages: leverages two brand equities, expands reach, shares costs, creates differentiation. Disadvantages: loss of control, brand dilution risk if partner has problems, complex agreements, may confuse consumers if not well executed.', 'Marketing'),
  tq('tmk49', 'Describe the different types of retailers and explain how retailing has evolved.', 'Retail types: (1) Department stores — wide variety, organised by departments (Macy\'s). (2) Supermarkets — self-service grocery, low margin, high volume. (3) Convenience stores — limited but convenient items, high prices (7-Eleven). (4) Discount stores — standard merchandise at low prices (Walmart). (5) Speciality stores — narrow line with deep assortment (Foot Locker). (6) Off-price retailers — brand-name goods at deep discounts (TJ Maxx). (7) Superstores — huge selection in specific categories (Best Buy). (8) Online retailers — e-commerce only (Amazon). Retail evolution: from small shops to large chains, from in-person to omnichannel (brick-and-click).', 'Marketing'),
  tq('tmk50', 'Explain the concept of supply chain management and contrast it with logistics management.', 'Supply chain management (SCM): managing upstream and downstream relationships with suppliers and channel partners to deliver superior customer value at lower cost. Includes all activities from raw material sourcing to final product delivery. Logistics: planning, implementing, and controlling the physical flow of materials and goods from point of origin to point of consumption. Logistics includes transportation, warehousing, inventory management, order processing, materials handling. SCM is broader — it includes logistics plus supplier relationships, channel relationships, demand planning, and coordination across the entire value chain.', 'Marketing'),
  tq('tmk51', 'Discuss the advantages and disadvantages of franchising as a distribution strategy.', 'Franchising: a contractual agreement where a franchisor grants a franchisee the right to operate a business using the franchisor\'s brand, systems, and support. Advantages to franchisor: rapid expansion with less capital, motivated operators, brand consistency, franchisee fees and royalties. Advantages to franchisee: proven business model, brand recognition, training and support, buying power, easier financing. Disadvantages: less control over franchisees, sharing profits, legal liability, quality consistency challenges. Disadvantages to franchisee: fees/royalties, strict operating rules, limited flexibility.', 'Marketing'),
  tq('tmk52', 'Explain the concept of marketing ethics and discuss the common ethical issues in marketing.', 'Marketing ethics: moral principles guiding marketing decisions and behaviour. Common ethical issues: (1) Deceptive advertising — false claims, misleading claims, bait-and-switch. (2) Targeting vulnerable groups — children, elderly, low-income with harmful products. (3) Price fixing and predatory pricing. (4) Product safety issues and planned obsolescence. (5) Invasion of privacy — data collection, tracking, targeted ads without consent. (6) Greenwashing — false environmental claims. (7) Stereotyping in advertising. Ethical marketing requires honesty, transparency, fairness, and responsibility.', 'Marketing'),
  tq('tmk53', 'Explain social responsibility in marketing and discuss the concept of cause-related marketing.', 'Social responsibility in marketing: companies should consider the long-term interests of society, not just short-term profits. Cause-related marketing: a company partners with a non-profit to promote a social cause while benefiting both (e.g., TOMS Shoes — buy one, give one). Benefits: improves brand image, differentiates, increases sales, builds customer loyalty, creates social impact. Criticisms: may be seen as exploitative, short-term, or superficial if not authentic. Effective cause marketing requires genuine alignment with brand values, transparency about contributions, and long-term commitment.', 'Marketing'),
  tq('tmk54', 'Discuss the concept of international marketing and explain the strategies for entering foreign markets.', 'International marketing: marketing across national boundaries. Entry strategies: (1) Exporting — indirect (through intermediaries) or direct (company handles). Least risk. (2) Joint ventures — partnering with foreign company (shared ownership, risk, control). (3) Licensing — licensor grants licensee right to use manufacturing process, trademark, etc. for a fee/royalty. (4) Franchising — service sector equivalent of licensing. (5) Direct investment — establishing wholly owned subsidiaries or manufacturing (highest risk, highest control). Strategies must consider political risk, cultural differences, legal systems, exchange rates, and infrastructure.', 'Marketing'),
  tq('tmk55', 'Explain how cultural differences affect international marketing strategies. Give examples.', 'Cultural factors affecting international marketing: (1) Language — translation issues (brand names may have negative meanings). Example: Chevrolet Nova (No va = \"doesn\'t go\" in Spanish). (2) Values and beliefs — attitudes toward time, work, family, consumption. (3) Customs — gift-giving, negotiation styles, business etiquette. (4) Aesthetics — colours have different meanings (white = purity in West, mourning in parts of Asia). (5) Religion — affects product acceptance, holidays, consumption patterns (halal food). (6) Social class and reference groups. Marketers must adapt to local cultural norms while maintaining brand consistency.', 'Marketing'),
  tq('tmk56', 'Describe the stages involved in developing an international marketing programme.', 'Stages: (1) Research international markets — evaluate potential (market size, growth, competition, political/economic stability). (2) Decide which markets to enter — based on market attractiveness and company capabilities. (3) Decide how to enter — export, joint venture, licensing, direct investment. (4) Decide marketing programme — adapt vs standardise. Standardisation: same marketing across countries (economies of scale, consistent brand image). Adaptation: customise to local markets (meets local needs better). (5) Organise the marketing effort — export department, international division, global organisation.', 'Marketing'),
  tq('tmk57', 'Explain what a product is at different levels: core product, actual product, and augmented product.', 'Three levels: (1) Core product — the fundamental benefit or problem-solving value the customer is really buying (e.g., a hotel guest buys \"rest and sleep\"). (2) Actual product — the tangible attributes: quality level, features, design, brand name, packaging (e.g., the hotel room with bed, bathroom, TV, furniture). (3) Augmented product — additional consumer services and benefits beyond the core and actual (e.g., free WiFi, breakfast, swimming pool, concierge service, loyalty points). Marketers compete increasingly at the augmented level.', 'Marketing'),
  tq('tmk58', 'Define wholesaling and explain the functions performed by wholesalers for manufacturers and retailers.', 'Wholesaling: all activities involved in selling goods and services to those buying for resale or business use. Functions: (1) Selling and promoting — manufacturer\'s sales force. (2) Buying and assortment building — selection of products for retailers. (3) Bulk breaking — purchasing large quantities, selling in smaller amounts. (4) Warehousing — storage, inventory management. (5) Transportation — delivery to retailers. (6) Financing — credit to retailers, inventory financing. (7) Risk bearing — theft, damage, obsolescence. (8) Market information — feedback to manufacturers. (9) Management services — training, merchandising advice.', 'Marketing'),
  tq('tmk59', 'Explain the concept of the marketing mix for services (7Ps) and apply each element to a service business of your choice.', '7Ps applied to a restaurant: (1) Product — food and beverage menu, quality, variety, taste. (2) Price — menu prices, value meals, discounts. (3) Place — location, delivery channels, online ordering. (4) Promotion — advertising, social media, loyalty cards, reviews. (5) People — chefs, waiters, managers, customer interaction, service attitude. (6) Process — ordering system, kitchen workflow, table service, payment procedure. (7) Physical evidence — restaurant decor, cleanliness, table settings, menu design, website. All 7Ps must be coordinated to deliver a consistent customer experience.', 'Marketing'),
  tq('tmk60', 'Explain the concept of niche marketing and provide examples of successful niche marketing strategies.', 'Niche marketing: focusing on a small, specific, well-defined market segment with unique needs that larger competitors overlook. Characteristics: small but profitable segment, specific customer needs, specialised offering, sustainable competitive advantage. Examples: (1) Lush — handmade, ethical, fresh cosmetics. (2) Rolls-Royce — ultra-luxury cars. (3) Beyond Meat — plant-based meat alternatives. (4) Fenty Beauty — wide shade range for diverse skin tones. Niche marketing can be more profitable than mass marketing despite smaller size due to premium pricing and customer loyalty.', 'Marketing'),
  tq('tmk61', 'Discuss the advantages and disadvantages of market segmentation.', 'Advantages: (1) Better understanding of customer needs leads to more targeted products. (2) Efficient use of marketing resources — reach the right customers. (3) Identify underserved segments — new market opportunities. (4) Stronger market position in specific segments. (5) Higher customer satisfaction and loyalty. Disadvantages: (1) Higher production and marketing costs (multiple products, campaigns). (2) Cannibalisation between segments. (3) Market fragmentation — segments may become too small. (4) Difficulty in segment measurement and accessibility. (5) Risk of over-segmentation.', 'Marketing'),
  tq('tmk62', 'Explain the AIDA model in advertising and describe how it works at each stage.', 'AIDA model: describes the stages a consumer goes through after seeing an advertisement. (1) Attention — the ad must grab the consumer\'s attention through visuals, headlines, sounds, novelty, or contrast. (2) Interest — after attention, the ad must generate interest by highlighting relevance, benefits, or unique selling points. (3) Desire — the ad must create a desire or preference for the product by appealing to emotions, showing how the product solves a problem or improves life. (4) Action — the ad must prompt action: a call to action (CTA) like \"Buy now,\" \"Visit our store,\" \"Call today.\"', 'Marketing'),
  tq('tmk63', 'What is a product line? Explain the strategies of product line stretching and product line filling.', 'Product line: a group of related products under one brand or category. Product line stretching: expanding the line beyond the current range. (1) Upward stretch — adding higher-priced, premium items (e.g., Toyota adding Lexus). (2) Downward stretch — adding lower-priced items to reach mass market (e.g., Apple iPhone SE). (3) Two-way stretch — adding both higher and lower-priced items (e.g., Marriott with Ritz-Carlton up and Fairfield Inn down). Product line filling: adding more items within the current price range (e.g., new flavours, sizes, variations).', 'Marketing'),
  tq('tmk64', 'Explain the concept of direct marketing and describe the main forms it takes.', 'Direct marketing: communicating directly with carefully targeted individual consumers to obtain an immediate response and cultivate lasting customer relationships. Forms: (1) Direct mail — catalogues, brochures, letters, CDs sent to physical addresses. (2) Telemarketing — outbound (cold calling) and inbound (toll-free numbers for ordering). (3) Direct-response television — infomercials, home shopping channels. (4) Kiosk marketing — customer-order machines (e.g., fast-food ordering kiosks). (5) Online marketing — websites, email, social media direct ads. (6) Mobile marketing — SMS, app notifications.', 'Marketing'),
  tq('tmk65', 'Explain the concept of word-of-mouth marketing (WOMM) and its effectiveness compared to traditional advertising.', 'Word-of-mouth marketing: the passing of information from person to person through oral communication. Buzz marketing: creating excitement and generating word-of-mouth. Effectiveness: WOMM is more credible (friends/family are trusted sources), cost-effective, has higher conversion rates, spreads quickly (especially through social media), and creates organic brand advocacy. Types: (1) Organic — naturally occurring conversations. (2) Amplified — company-initiated (referral programmes, social sharing incentives). (3) Viral — content that spreads like a virus.', 'Marketing'),
  tq('tmk66', 'Describe the difference between a market and an industry. Explain the types of markets a company can operate in.', 'Market: set of actual and potential buyers of a product (demand side). Industry: set of companies that supply the market (supply side). Market types: (1) Consumer market — individuals/households buying for personal consumption. (2) Business market — organisations buying for production of other goods/services. (3) Reseller market — intermediaries buying to resell at profit. (4) Government market — government agencies buying for public services. (5) International market — buyers in foreign countries. Each type has distinct buying behaviour, decision processes, and marketing approaches.', 'Marketing'),
  tq('tmk67', 'Explain the concept of product differentiation and discuss ways to differentiate a product.', 'Product differentiation: making a product distinct from competitors on attributes valued by customers. Differentiation bases: (1) Product — features, performance, quality, durability, reliability, repairability, style, design. (2) Service — ordering ease, delivery, installation, customer training, maintenance, returns. (3) Personnel — competence, courtesy, credibility, reliability, responsiveness, communication skills. (4) Channel — coverage, expertise, performance. (5) Image — symbols, brands, media, atmosphere, events. Successful differentiation must be important, distinctive, superior, communicable, preemptive, affordable, and profitable.', 'Marketing'),
  tq('tmk68', 'Discuss the factors to consider when setting the advertising budget.', 'Factors: (1) Stage in the product life cycle — new products need higher budgets. (2) Market share and consumer base — high-share brands need less as % of sales. (3) Competition and clutter — more competitors/clutter requires greater spending. (4) Advertising frequency — repetition needed for brand-building. (5) Product substitutability — undifferentiated brands need more advertising. Budget methods: (1) Affordable method — what the company can afford. (2) Percentage of sales — fixed % of past/forecast sales. (3) Competitive parity — match competitors. (4) Objective and task — define objectives, determine tasks, estimate costs.', 'Marketing'),
  tq('tmk69', 'Explain how online consumer behaviour differs from offline consumer behaviour.', 'Differences: (1) Greater control — consumers actively search, compare, filter rather than passively receive. (2) More information — access to reviews, ratings, detailed product specs, price comparison sites. (3) Reduced search costs — easier, faster to compare alternatives. (4) Higher price sensitivity — easier to find the best price. (5) Trust considerations — privacy concerns, security, credibility of online sellers. (6) Social influence — online reviews, social media recommendations strongly influence decisions. (7) Impulse buying — facilitated by one-click ordering, targeted ads.', 'Marketing'),
  tq('tmk70', 'Describe the role of sales promotion in the promotional mix and its advantages and limitations.', 'Sales promotion: short-term incentives to encourage purchase or sale of a product. Advantages: (1) Quick results — stimulates immediate purchase. (2) Measurable — easy to track response. (3) Flexible — can target specific segments/timing. (4) Encourages trade support. Limitations: (1) May damage brand image if too frequent (appears cheap). (2) Attracts deal-prone buyers (not loyal). (3) Short-term focus — does not build long-term preference. (4) May cannibalise regular sales. (5) Competitors can easily match. Best used with advertising for long-term brand building plus short-term response.', 'Marketing'),
  tq('tmk71', 'Explain Maslow\'s hierarchy of needs and its application in marketing.', 'Maslow\'s hierarchy (5 levels): (1) Physiological — basic survival (food, water, shelter). Marketing: grocery stores, bottled water, housing ads. (2) Safety — security, protection, stability. Marketing: insurance, alarm systems, health products. (3) Social — belonging, love, relationships. Marketing: social media platforms, dating apps, family-oriented products. (4) Esteem — recognition, status, respect. Marketing: luxury brands, premium cars, designer clothing. (5) Self-actualisation — reaching full potential. Marketing: self-help books, education, meditation apps. Marketers appeal to the relevant need level for their target market.', 'Marketing'),
  tq('tmk72', 'Discuss the advantages and disadvantages of online retailing (e-commerce) compared to brick-and-mortar retailing.', 'E-commerce advantages: (1) Convenience — shop anytime, anywhere. (2) Wider selection — unlimited shelf space. (3) Lower prices — lower overhead costs. (4) Easy comparison shopping. (5) Customer reviews and recommendations. (6) Personalisation. Disadvantages: (1) Cannot physically examine products before purchase. (2) Delayed gratification — waiting for delivery. (3) Shipping costs and returns. (4) Security and privacy concerns. (5) Lack of personal interaction. Brick-and-mortar advantages: touch/feel products, instant gratification, personal service, social experience. Successful retailers use omnichannel.', 'Marketing'),
  tq('tmk73', 'Explain the concept of the marketing environment and describe how companies should respond to environmental changes.', 'Marketing environment: all external factors that affect marketing decisions. Reactive approach: accepting the environment as uncontrollable and adapting. Proactive approach: taking action to change the environment. Environmental scanning: systematically collecting information about external forces. Companies should: (1) Monitor continuously for changes and trends. (2) Assess impact on business. (3) Adapt strategies proactively. (4) Look for opportunities in environmental changes. (5) Develop contingency plans. Environmental management includes lobbying, strategic alliances, PR to shape public opinion, and litigation.', 'Marketing'),
  tq('tmk74', 'Describe the concept of value proposition and what makes a value proposition effective.', 'Value proposition: a set of benefits that a company promises to deliver to customers to satisfy their needs. It answers \"Why should I buy from you?\" Effective value propositions are: (1) Clear — easy to understand (e.g., M&M\'s \"Melts in your mouth, not in your hand\"). (2) Relevant — addresses specific customer needs. (3) Unique — different from competitors. (4) Credible — believable and deliverable. (5) Specific — concrete, not vague. (6) Compelling — motivates purchase. Examples: Volvo (safety), Apple (simplicity + design), FedEx (guaranteed overnight delivery).', 'Marketing'),
  tq('tmk75', 'Explain the different types of advertising: informative, persuasive, reminder, and reinforcement.', '(1) Informative advertising — used when introducing a new product, building primary demand. Objectives: inform about product features, announce price changes, explain how it works. (2) Persuasive advertising — used in competitive growth/maturity stage. Objectives: build brand preference, encourage switching. Comparative advertising directly compares with competitors (e.g., Pepsi vs Coke). (3) Reminder advertising — used for mature, well-known products to keep brand in mind. (4) Reinforcement advertising — assures current customers they made the right choice, reducing cognitive dissonance.', 'Marketing'),
  tq('tmk76', 'Discuss the factors that influence the selection of advertising media.', 'Factors: (1) Reach — number of different people exposed. (2) Frequency — how often target is exposed. (3) Impact — qualitative value of exposure. (4) Target audience characteristics — age, lifestyle, media habits. (5) Product characteristics — visual products need TV/Instagram, complex products need print. (6) Message requirements — demonstration, explanation, emotion. (7) Cost — absolute cost and cost per thousand (CPM). (8) Media availability and schedule. Major media: TV (broad reach, high impact, expensive), radio (targeted, low cost), newspapers (local, timely), magazines (targeted, high quality), outdoor (mass, low cost), digital (targeted, measurable).', 'Marketing'),
  tq('tmk77', 'Explain the concept of relationship marketing and how it differs from transactional marketing.', 'Relationship marketing: building long-term, mutually satisfying relationships with key parties (customers, suppliers, distributors) to earn and retain their business. Transactional marketing: focus on individual sales transactions with short-term perspective. Differences: Transactional — single sale, product features, limited customer service, moderate customer contact. Relationship — customer retention, customer benefits, high customer service, high customer contact, quality from all functions. Relationship marketing uses CRM, loyalty programmes, personalisation, and customer engagement to build lasting relationships.', 'Marketing'),
  tq('tmk78', 'What is a marketing channel? Explain the concept of channel conflict and how it can be managed.', 'Marketing channel: a set of interdependent organisations involved in the process of making a product available for consumption. Channel conflict: disagreements among channel members about goals, roles, or rewards. Types: (1) Horizontal — conflict between members at the same level (e.g., two retailers). (2) Vertical — conflict between different levels (e.g., manufacturer vs retailer). (3) Multi-channel — conflict when company uses multiple channels that compete. Management: set superordinate goals, appoint channel captains, use mediation/arbitration, exchange programmes, build strong relationships, develop clear channel policies.', 'Marketing'),
  tq('tmk79', 'Explain the concept of green marketing and its importance in today\'s business environment.', 'Green marketing: marketing activities that aim to satisfy customer needs while being environmentally responsible. Aspects: (1) Product — eco-friendly design, sustainable materials, recyclable packaging. (2) Price — may be higher (premium for green) but acceptable to eco-conscious consumers. (3) Promotion — communicating environmental benefits (must be credible to avoid greenwashing). (4) Place — sustainable logistics. Importance: growing consumer environmental awareness, regulatory requirements, cost savings (energy efficiency), competitive differentiation, positive brand image. Examples: Patagonia (repair programme), IKEA (sustainable materials), Tesla (electric vehicles).', 'Marketing'),
  tq('tmk80', 'Discuss the concept of customer lifetime value (CLV) and explain how it is calculated.', 'Customer lifetime value (CLV): the net present value of all future profits a company expects to earn from a customer relationship. Simplified formula: CLV = Average purchase value x Purchase frequency x Customer lifespan x Profit margin. Importance: (1) Helps determine how much to spend on acquiring customers. (2) Identifies most valuable customers for retention. (3) Guides resource allocation. (4) Shows value of loyalty programmes. Companies can increase CLV by increasing purchase frequency, raising average order value, extending customer lifespan, and reducing service costs.', 'Marketing'),
  tq('tmk81', 'Explain the difference between goods and services. Discuss the implications of service characteristics for marketing.', 'Goods: tangible products that can be produced, stored, and transported. Services: intangible activities/benefits provided in exchange. Service characteristics: (1) Intangibility — cannot be touched or inspected before purchase. Implication: use tangible cues, testimonials, guarantees. (2) Inseparability — produced and consumed simultaneously. Implication: manage service encounters, train employees. (3) Heterogeneity — quality varies. Implication: standardise processes, training, quality systems. (4) Perishability — cannot be stored. Implication: manage supply and demand (reservations, dynamic pricing, part-time staff).', 'Marketing'),
  tq('tmk82', 'Explain the stages of the adoption process for new products.', 'Adoption process (5 stages): (1) Awareness — consumer becomes aware of the innovation but lacks information. (2) Interest — consumer is stimulated to seek information about the innovation. (3) Evaluation — consumer considers whether to try the innovation. (4) Trial — consumer tries the product on a limited basis (samples, test drives). (5) Adoption — consumer decides to make full regular use. The process is supported by diffusion of innovation theory — different adopter categories move through these stages at different times. Marketers facilitate movement through each stage.', 'Marketing'),
  tq('tmk83', 'Describe the different types of buying decision behaviour in consumer markets.', '(1) Complex buying behaviour — high involvement, significant differences between brands. Consumer goes through thorough information search and evaluation. Examples: house, car. Strategy: provide detailed information, educate. (2) Dissonance-reducing behaviour — high involvement, few brand differences. Strategy: provide reassurance, post-purchase communication. (3) Habitual buying behaviour — low involvement, few brand differences. Strategy: repetitive advertising, shelf placement, price promotions. (4) Variety-seeking behaviour — low involvement, significant brand differences. Strategy: encourage trial, dominate shelf space, advertise to remind.', 'Marketing'),
  tq('tmk84', 'Explain the difference between a push and a pull supply chain strategy.', 'Push strategy: supply chain based on forecasted demand. Products are produced and pushed through the channel. Characteristics: production based on forecasts, inventory buildup, economies of scale, longer lead times, higher inventory risk. Pull strategy: supply chain responds to actual customer demand. Characteristics: produce to order, lower inventory, just-in-time (JIT) manufacturing, faster response, more flexible. Examples: Dell (build-to-order), Zara (fast fashion). Most companies use a hybrid (push-pull) — push for predictable demand, pull for uncertain demand.', 'Marketing'),
  tq('tmk85', 'Discuss the role of marketing in non-profit organisations. How does it differ from for-profit marketing?', 'Non-profit marketing: applying marketing principles to achieve social objectives rather than profit. Differences: (1) Objective — social change vs profit. (2) Target — multiple publics (donors, beneficiaries, volunteers) vs customers. (3) Product — often intangible ideas/services vs tangible goods. (4) Pricing — free or subsidised vs market price. (5) Promotion — rely more on PR, cause marketing, community outreach vs paid advertising. (6) Evaluation — difficult to measure ROI vs clear sales data. Examples: charity campaigns, anti-smoking campaigns, environmental conservation awareness.', 'Marketing'),
  tq('tmk86', 'Explain the concept of market positioning and perceptual mapping. Draw and explain a perceptual map for the automobile industry.', 'Market positioning: designing the company\'s offering and image to occupy a distinctive place in the target consumer\'s mind. Perceptual mapping: a visual technique to display consumer perceptions of brands on key attributes. For automobile industry (axes: price low to high, luxury to practical): Top-right (high price, luxury): Mercedes-Benz, BMW, Lexus. Top-left (high price, practical): Volvo. Bottom-right (low price, luxury): Mini Cooper. Bottom-left (low price, practical): Toyota, Honda. Perceptual maps help identify competitive positions, gaps in the market, and repositioning opportunities.', 'Marketing'),
  tq('tmk87', 'Describe the major types of marketing organisation structures.', '(1) Functional organisation — marketing activities grouped by functions (advertising, sales, research, customer service). Simple for small companies. (2) Geographic organisation — sales and marketing organised by regions, countries. (3) Product management organisation — product manager responsible for each product line. Used by multi-product companies (P&G). (4) Market/customer management organisation — managers responsible for specific customer segments. Customer-focused. (5) Matrix organisation — combination of functional, product, and geographic structures. Complex but flexible. No single best structure.', 'Marketing'),
  tq('tmk88', 'Explain the concept of experiential marketing and why it is effective.', 'Experiential marketing: creating memorable experiences that engage consumers emotionally, physically, intellectually, or socially with a brand. Examples: pop-up stores, brand events, sampling with demonstrations, virtual reality experiences, sponsored festivals. Why effective: (1) Creates emotional connection leads to stronger brand attachment. (2) Memorable — experiences last longer than ads. (3) Personal — involves the consumer directly. (4) Shareable — consumers share experiences on social media. (5) Differentiation — experiences stand out in a cluttered market. (6) Builds community among brand enthusiasts.', 'Marketing'),
  tq('tmk89', 'Explain how companies use loyalty programmes to build customer retention and what makes them effective.', 'Loyalty programmes: structured marketing efforts that reward customers for repeat purchasing. Types: (1) Points-based — earn points per purchase, redeem for rewards (airline miles). (2) Tiered — different levels with increasing benefits (Gold, Platinum). (3) Paid membership — customers pay for benefits (Amazon Prime). (4) Value-based — rewards aligned with brand values. Effectiveness factors: (1) Real value — rewards genuinely attractive. (2) Achievable — customers can realistically earn rewards. (3) Simple — easy to understand. (4) Emotional benefits — recognition, status, belonging. (5) Personalisation — relevant offers.', 'Marketing'),
  tq('tmk90', 'Describe the difference between a market follower strategy and a market challenger strategy.', 'Market challenger: a firm that aggressively attacks the market leader and competitors to gain market share. Attack strategies: (1) Frontal attack — head-on against leader. (2) Flank attack — target leader\'s weaknesses. (3) Encirclement — simultaneous attack on all fronts. (4) Bypass — develop new technology/products. (5) Guerrilla — periodic small attacks (price cuts). Market follower: a firm that imitates the leader\'s products and policies to maintain market share without rocking the boat. Types: (1) Adapter — copies and improves. (2) Imitator — copies the leader\'s products. (3) Cloner — copies the leader\'s entire offering.', 'Marketing'),
  tq('tmk91', 'Explain the concept of marketing control and describe the types of marketing control.', 'Marketing control: measuring and evaluating results of marketing strategies and plans, and taking corrective action. Types: (1) Annual plan control — monitoring current marketing efforts to ensure sales and profit goals are achieved. Tools: sales analysis, market share analysis, expense-to-sales ratio analysis. (2) Profitability control — measuring actual profitability of products, territories, segments, channels. (3) Efficiency control — evaluating efficiency of sales force, advertising, promotion, distribution. (4) Strategic control — evaluating whether marketing strategies are appropriate. Tools: marketing audit.', 'Marketing'),
  tq('tmk92', 'Explain the concept of market share and the different ways to measure it. Why is market share important?', 'Market share: the percentage of an industry\'s total sales earned by a particular company. Measurements: (1) Overall market share — company sales / total industry sales. (2) Served market share — company sales / total sales in its target market. (3) Relative market share — company share / largest competitor\'s share. Importance: (1) Indicator of competitive strength. (2) Higher share often means higher profitability (scale economies). (3) Shows whether strategies are working. (4) Investors use it to evaluate performance. Limitations: industry definition affects calculation; may not reflect profitability.', 'Marketing'),
  tq('tmk93', 'Explain the concept of viral marketing and the factors that make content go viral.', 'Viral marketing: digital marketing technique that uses social networks and word-of-mouth to spread brand messages exponentially, similar to a virus. Factors for viral success: (1) Emotional appeal — content that evokes strong emotions (humour, awe, anger, joy) is more shareable. (2) Social currency — content that makes people look smart, funny, or in-the-know. (3) Triggers — reminders in the environment that make people think of the brand. (4) Practical value — useful content people want to share. (5) Storytelling — compelling, authentic narratives. (6) Network effects — platforms that facilitate sharing.', 'Marketing'),
  tq('tmk94', 'Explain the difference between convenience goods, shopping goods, speciality goods, and unsought goods.', 'Classification by consumer shopping habits: (1) Convenience goods — frequently purchased, minimal effort, low price (toothpaste, bread). Distribution: intensive. Promotion: mass advertising. (2) Shopping goods — compared on quality, price, style (furniture, electronics). Distribution: selective. Promotion: advertising and personal selling. (3) Speciality goods — unique characteristics, strong brand identification, special effort to buy (luxury cars, designer clothes). Distribution: exclusive. Promotion: targeted advertising. (4) Unsought goods — products consumers don\'t normally consider (life insurance). Requires aggressive promotion.', 'Marketing'),
  tq('tmk95', 'Explain the concept of Ansoff\'s matrix (product-market expansion grid) for growth strategies.', 'Ansoff\'s matrix: strategic planning tool mapping growth strategies based on products (existing/new) and markets (existing/new). Four strategies: (1) Market penetration — existing products, existing markets. Grow market share through price cuts, advertising, more distribution. Lowest risk. (2) Product development — new products, existing markets. New features, models, brand extensions. (3) Market development — existing products, new markets. New geographic areas, new demographic segments. (4) Diversification — new products, new markets. Highest risk. Types: concentric (related to existing business), horizontal, conglomerate (unrelated).', 'Marketing'),
  tq('tmk96', 'Discuss the advantages and challenges of global marketing for companies.', 'Advantages: (1) Larger market — access to billions of consumers. (2) Economies of scale — lower per-unit costs. (3) Risk diversification — less dependent on one economy. (4) Access to cheaper resources/labour. (5) Extend product life cycle. (6) Learn from different markets. Challenges: (1) Cultural differences — language, customs, values. (2) Legal/regulatory differences — product standards, advertising rules. (3) Currency fluctuations — exchange rate risk. (4) Political risk — instability, expropriation. (5) Distribution complexity. (6) Competitive differences. (7) Coordination across time zones and distances.', 'Marketing'),
  tq('tmk97', 'Explain the concept of integrated marketing communications (IMC) and its importance.', 'Integrated Marketing Communications (IMC): coordinating all promotional tools (advertising, PR, personal selling, sales promotion, direct marketing, digital) to deliver a clear, consistent, and compelling message about a brand. Importance: (1) Consistency — all communications speak with one voice. (2) Synergy — combined effect exceeds individual effects. (3) Efficiency — reduces duplication and waste. (4) Brand building — consistent messaging strengthens brand identity. (5) Customer perspective — customers see a unified brand across all touchpoints. IMC requires breaking down silos between departments and agencies.', 'Marketing'),
  tq('tmk98', 'Describe the process of creating a marketing plan. What are the key sections?', 'Marketing plan: a written document summarising market situation, objectives, strategy, actions, and controls. Key sections: (1) Executive summary — brief overview of main goals. (2) Current marketing situation — market description, product review, competitive review, SWOT analysis. (3) Objectives — specific, measurable, achievable, relevant, time-bound (SMART) goals. (4) Target market — description of segments being served. (5) Marketing strategy — positioning, marketing mix (4Ps/7Ps), budget. (6) Action programmes — what will be done, by whom, when, cost. (7) Budget — projected profit and loss. (8) Controls — how performance will be monitored.', 'Marketing'),
  tq('tmk99', 'Explain the concept of benchmarking in marketing and how companies use competitor analysis.', 'Benchmarking: comparing the company\'s products, processes, and performance against best-in-class competitors or industry standards. Competitor analysis: identifying key competitors, assessing their objectives, strategies, strengths, weaknesses, and reaction patterns. Steps: (1) Identify competitors — brand, industry, form, generic. (2) Assess competitors — objectives, strategies, strengths/weaknesses, reaction patterns. (3) Select which competitors to attack/avoid. Benchmarking focuses on products, costs, customer service, processes, or marketing. The goal is to learn, improve, and gain competitive advantage through continuous improvement.', 'Marketing'),
  tq('tmk100', 'Discuss the future trends in marketing and how technology is transforming the field.', 'Future trends: (1) AI and automation — chatbots, personalised recommendations, programmatic advertising. (2) Big data — deeper customer insights, micro-segmentation. (3) Personalisation at scale — individualised messages and offers. (4) Voice search — optimising for voice queries. (5) AR/VR — virtual try-ons, immersive brand experiences. (6) Social commerce — buying directly on social platforms. (7) Sustainability — purpose-driven marketing. (8) Privacy — data protection regulations, cookie-less tracking. (9) Influencer marketing maturity — micro-influencers. (10) Omnichannel integration — seamless experience across all channels.', 'Marketing'),
]
